# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
users_collection = db['users']

@app.route('/user', methods=['POST'])
def create_user():
    user_data = request.json
    result = users_collection.insert_one(user_data)
    return jsonify({'message': 'User created successfully', 'user_id': str(result.inserted_id)}), 201

@app.route('/user/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users_collection.find_one({'_id': user_id})
    if user:
        return jsonify(user)
    else:
        return jsonify({'message': 'User not found'}), 404

@app.route('/users', methods=['GET'])
def get_users():
    users = list(users_collection.find())
    return jsonify(users)

@app.route('/user/<user_id>/profile', methods=['PUT'])
def update_user_profile(user_id):
    user_data = request.json
    result = users_collection.update_one({'_id': user_id}, {'$set': user_data})
    if result.modified_count > 0:
        return jsonify({'message': 'User profile updated successfully'})
    else:
        return jsonify({'message': 'User not found'}), 404

@app.route('/documents', methods=['POST'])
def create_document():
    document_data = request.json
    result = users_collection.insert_one(document_data)
    return jsonify({'message': 'Document created successfully', 'document_id': str(result.inserted_id)}), 201

@app.route('/documents/<document_id>', methods=['GET'])
def get_document(document_id):
    document = users_collection.find_one({'_id': document_id})
    if document:
        return jsonify(document)
    else:
        return jsonify({'message': 'Document not found'}), 404

@app.route('/documents', methods=['GET'])
def get_documents():
    documents = list(users_collection.find())
    return jsonify(documents)

@app.route('/documents/aggregation', methods=['POST'])
def documents_aggregation():
    pipeline = request.json
    result = users_collection.aggregate(pipeline)
    return jsonify(list(result))

if __name__ == '__main__':
    app.run(debug=True)